// Extract clips from the API response
const clips = $input.first().json.magicClips || [];

// Transform each clip into a separate item
return clips.map((clip, index) => ({
  json: {
    clip_number: index + 1,
    clip_id: clip.id,
    title: clip.title,
    duration: clip.duration,
    virality_score: clip.viralityScores?.total || 0,
    download_url: clip.downloadUrl,
    youtube_id: $('New Video Added').item.json.youtube_url.split('v=')[1] || '',
    project_id: $input.first().json.id
  }
}));
